#!/usr/bin/env bash
set -euo pipefail
REPO="${1:-$HOME/freddy-fixit}"
[ -d "$REPO/.git" ] || { for d in "$HOME/Desktop/Website/freddy-fixit" "$HOME/freddy-fixit" "$HOME/Desktop/freddy-fixit"; do [ -d "$d/.git" ] && REPO="$d" && break; done; }
[ -d "$REPO/.git" ] || { echo "❌ repo not found"; exit 1; }
cd "$REPO"
decode() { mkdir -p "$(dirname "$1")"; base64 -d < "$2" > "$1"; }
TMP="$(mktemp -d)"
cat > "$TMP/CLAUDE_md.b64" <<'B64EOF'

B64EOF
decode "CLAUDE.md" "$TMP/CLAUDE_md.b64"
cat > "$TMP/src_App_tsx.b64" <<'B64EOF'

B64EOF
decode "src/App.tsx" "$TMP/src_App_tsx.b64"
cat > "$TMP/src_pages_ClientDashboard_tsx.b64" <<'B64EOF'

B64EOF
decode "src/pages/ClientDashboard.tsx" "$TMP/src_pages_ClientDashboard_tsx.b64"
cat > "$TMP/src_pages_ContractorDashboard_tsx.b64" <<'B64EOF'

B64EOF
decode "src/pages/ContractorDashboard.tsx" "$TMP/src_pages_ContractorDashboard_tsx.b64"
cat > "$TMP/src_pages_AdminDashboard_tsx.b64" <<'B64EOF'

B64EOF
decode "src/pages/AdminDashboard.tsx" "$TMP/src_pages_AdminDashboard_tsx.b64"
cat > "$TMP/src_pages_Home_tsx.b64" <<'B64EOF'

B64EOF
decode "src/pages/Home.tsx" "$TMP/src_pages_Home_tsx.b64"
cat > "$TMP/src_pages_UserAgreement_tsx.b64" <<'B64EOF'

B64EOF
decode "src/pages/UserAgreement.tsx" "$TMP/src_pages_UserAgreement_tsx.b64"
cat > "$TMP/src_components_ReportProblem_tsx.b64" <<'B64EOF'

B64EOF
decode "src/components/ReportProblem.tsx" "$TMP/src_components_ReportProblem_tsx.b64"
cat > "$TMP/src_components_RespondToClaim_tsx.b64" <<'B64EOF'

B64EOF
decode "src/components/RespondToClaim.tsx" "$TMP/src_components_RespondToClaim_tsx.b64"
cat > "$TMP/supabase_functions_create-payment-intent_index_ts.b64" <<'B64EOF'

B64EOF
decode "supabase/functions/create-payment-intent/index.ts" "$TMP/supabase_functions_create-payment-intent_index_ts.b64"
cat > "$TMP/supabase_functions_stripe-webhook_index_ts.b64" <<'B64EOF'

B64EOF
decode "supabase/functions/stripe-webhook/index.ts" "$TMP/supabase_functions_stripe-webhook_index_ts.b64"
rm -rf "$TMP"
git add -A
git commit -m "Claims/dispute process, scroll-to-top, remove free-quote home button" || { echo "nothing to commit"; exit 0; }
git push
echo "✅ pushed"
